mapper.insert:
INSERT INTO equipment_asset (
    equipment_asset_id, equipment_id, purchase_date, purchase_amount,
    purchase_store, purchase_store_contact, purchase_store_postal_code, purchase_store_address,
    warranty_expiry_date, purchase_quantity, remarks, created_at, updated_at
) VALUES (
    #{equipmentAssetId}, #{equipmentId}, #{purchaseDate}, #{purchaseAmount},
    #{purchaseStore}, #{purchaseStoreContact}, #{purchaseStorePostalCode}, #{purchaseStoreAddress},
    #{warrantyExpiryDate}, #{purchaseQuantity}, #{remarks}, #{createdAt}, #{updatedAt}
)

mapper.update:
UPDATE equipment_asset
SET deleted_at = #{deletedAt}, updated_at = #{deletedAt}
WHERE equipment_asset_id = #{equipmentAssetId} AND deleted_at IS NULL

mapper.select:
SELECT ea.equipment_asset_id, ea.equipment_id, e.name AS equipment_name, ea.purchase_date, ea.purchase_amount, ea.purchase_store, ea.purchase_store_contact, ea.purchase_store_postal_code, ea.purchase_store_address, ea.warranty_expiry_date, ea.purchase_quantity, ea.remarks, ea.created_at, ea.updated_at FROM equipment_asset ea INNER JOIN equipment e ON e.equipment_id = ea.equipment_id AND e.deleted_at IS NULL WHERE ea.deleted_at IS NULL
AND ea.equipment_id = #{equipmentId}
ORDER BY ea.equipment_asset_id DESC LIMIT #{limit} OFFSET #{offset}
